    style F fill:#16a34a,stroke:#4ade80,color:#ffffff
    style G fill:#dc2626,stroke:#f87171,color:#ffffff
    style H fill:#dc2626,stroke:#f87171,color:#ffffff
    style X1 fill:#fbbf24,stroke:#f59e0b,color:#000000
    style Y1 fill:#22c55e,stroke:#86efac,color:#000000
    style Y2 fill:#ef4444,stroke:#fca5a5,color:#000000
