#### Model Solution for Q.A(b):

```javascript
const express = require('express');
const app = express();
const PORT = 3000;

// In-memory data store
let books = [
  { id: 1, title: 'Clean Code', author: 'Robert C. Martin' },
  { id: 2, title: 'The Pragmatic Programmer', author: 'Andy Hunt' }
];
let nextId = 3;

// Built-in middleware
app.use(express.json());

// (i) GET /books — Retrieve all books
app.get('/books', (req, res) => {
  res.status(200).json({
    success: true,
    count: books.length,
    data: books
  });
});

// (ii) GET /books/:id — Retrieve a specific book
app.get('/books/:id', (req, res) => {
  const id = parseInt(req.params.id);
  const book = books.find(b => b.id === id);
  if (!book) {
    return res.status(404).json({
      success: false,
      error: `Book with id ${id} not found`
    });
  }
  res.status(200).json({ success: true, data: book });
});

// (iii) POST /books — Add a new book
app.post('/books', (req, res) => {
  const { title, author } = req.body;
  // Validation
  if (!title || !author) {
    return res.status(400).json({
      success: false,
      error: 'Both "title" and "author" fields are required'
    });
  }
  const newBook = { id: nextId++, title, author };
  books.push(newBook);
  res.status(201).json({
    success: true,
    message: 'Book created successfully',
    data: newBook
  });
});

// (iv) DELETE /books/:id — Remove a book
app.delete('/books/:id', (req, res) => {
  const id = parseInt(req.params.id);
  const index = books.findIndex(b => b.id === id);
  if (index === -1) {
    return res.status(404).json({
      success: false,
      error: `Book with id ${id} not found`
    });
  }
  const deletedBook = books.splice(index, 1);
  res.status(200).json({
    success: true,
    message: 'Book deleted successfully',
    data: deletedBook[0]
  });
});

// 404 catch-all
app.use((req, res) => {
  res.status(404).json({ success: false, error: 'Route not found' });
});

// Start server
app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});
```

