#### Model Solution for Q.B(b):

```javascript
const express = require('express');
const app = express();
const PORT = 3000;

// ======= MIDDLEWARE 1: Body Parser (Built-in) =======
app.use(express.json());

// ======= MIDDLEWARE 2: Request Logger (Custom Application-Level) =======
const logger = (req, res, next) => {
  const time = new Date().toISOString();
  console.log(`[${time}] ${req.method} ${req.originalUrl}`);
  next();
};
app.use(logger);

// ======= MIDDLEWARE 3: API Key Validator (Custom) =======
const validateApiKey = (req, res, next) => {
  const apiKey = req.query.apikey || req.headers['x-api-key'];
  if (apiKey !== 'ktu-secret-2024') {
    return res.status(401).json({ error: 'Invalid or missing API key' });
  }
  next();
};

// ======= Data Store =======
let users = [
  { id: 1, name: 'Rahul', email: 'rahul@ktu.edu', role: 'student' },
  { id: 2, name: 'Priya', email: 'priya@ktu.edu', role: 'faculty' }
];
let nextId = 3;

// ======= ROUTE: GET /users =======
// Demonstrates: Query String Filtering + Route Parameters
app.get('/users', (req, res) => {
  const { role, name } = req.query;   // Query string access
  let result = users;
  if (role) result = result.filter(u => u.role === role);
  if (name) result = result.filter(u => u.name.toLowerCase().includes(name.toLowerCase()));
  res.status(200).json({ count: result.length, data: result });
});

// ======= ROUTE: GET /users/:id =======
app.get('/users/:id', (req, res, next) => {
  try {
    const id = parseInt(req.params.id);
    if (isNaN(id)) {
      const err = new Error('Invalid ID format — must be numeric');
      err.status = 400;
      throw err;
    }
    const user = users.find(u => u.id === id);
    if (!user) {
      const err = new Error(`User with id ${id} not found`);
      err.status = 404;
      throw err;
    }
    res.status(200).json(user);
  } catch (err) {
    next(err);   // Forward to error-handling middleware
  }
});

// ======= ROUTE: POST /users (Protected by validateApiKey) =======
app.post('/users', validateApiKey, (req, res) => {
  const { name, email, role } = req.body;
  if (!name || !email) {
    return res.status(400).json({ error: 'Fields "name" and "email" are mandatory' });
  }
  const newUser = { id: nextId++, name, email, role: role || 'student' };
  users.push(newUser);
  res.status(201).json({ message: 'User created', data: newUser });
});

// ======= ROUTE: DELETE /users/:id (Protected) =======
app.delete('/users/:id', validateApiKey, (req, res) => {
  const id = parseInt(req.params.id);
  const index = users.findIndex(u => u.id === id);
  if (index === -1) {
    return res.status(404).json({ error: 'User not found' });
  }
  const deleted = users.splice(index, 1);
  res.status(200).json({ message: 'User deleted', data: deleted[0] });
});

// ======= ERROR-HANDLING MIDDLEWARE (4-arg signature) =======
app.use((err, req, res, next) => {
  console.error('❌ Error:', err.message);
  res.status(err.status || 500).json({
    success: false,
    error: err.message || 'Internal Server Error'
  });
});

// ======= Start Server =======
app.listen(PORT, () => {
  console.log(`🚀 Server running at http://localhost:${PORT}`);
});
```

**Demonstrated Concepts:**

| Concept | Where Used |
|---|---|
| Built-in middleware | `express.json()` |
| Custom application-level middleware | `logger`, `validateApiKey` |
| Route parameters | `req.params.id` in `GET /users/:id` |
| Query strings | `req.query.role`, `req.query.name`, `req.query.apikey` |
| Request body parsing | `req.body` in `POST /users` |
| HTTP status codes | `200`, `201`, `400`, `401`, `404`, `500` |
| Error-handling middleware | Final `app.use((err, req, res, next) => ...)` |

