# 3. Step-by-Step Implementation Matrix

> [!IMPORTANT]
> KTU Module 4 expects **Node.js / Express.js** implementation evidence. The following derivations show the exact transition from a logged-in state to a logged-out state, both for **stateful** (Express-Session) and **stateless** (JWT) architectures. Every line is preserved — no shortcuts.

## 3.1 Stateful Logout — Express-Session Derivation

### Step 1 — Application Skeleton & Dependencies

```javascript
// app.js (stateful logout derivation)
const express    = require('express');
const session    = require('express-session');
const MongoStore = require('connect-mongo');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));
```

**Logic:** `express` is the HTTP server, `express-session` is the middleware that attaches `req.session`, `connect-mongo` persists sessions in MongoDB so logout truly removes them from disk.

### Step 2 — Mount the Session Middleware

```javascript
app.use(session({
  name: 'connect.sid',
  secret: process.env.SESSION_SECRET || 'ktu-super-secret-key',
  resave: false,
  saveUninitialized: false,
  store: MongoStore.create({ mongoUrl: 'mongodb://127.0.0.1:27017/ktuApp' }),
  cookie: {
    httpOnly: true,
    secure: false,          // set true in production (HTTPS)
    sameSite: 'lax',
    maxAge: 1000 * 60 * 30   // 30 minutes
  }
}));
```

**Logic:** `httpOnly` blocks JS access, `sameSite=lax` prevents CSRF, `maxAge` defines $T_{s}$.

### Step 3 — A Minimal Login (Sets the Session)

```javascript
app.post('/login', (req, res) => {
  const { username, password } = req.body;
  if (username === 'admin' && password === 'ktu123') {
    req.session.userId   = 'admin-001';
    req.session.role     = 'student';
    req.session.loggedIn = true;
    return res.status(200).json({ message: 'Login successful' });
  }
  return res.status(401).json({ error: 'Invalid credentials' });
});
```

**Logic:** Only after `req.session.userId` is written does the session ID become meaningful; logout must undo exactly this.

### Step 4 — The Logout Endpoint (Core Derivation)

```javascript
app.post('/logout', (req, res) => {

  // Sub-step 4.1: Verify a session actually exists (idempotency)
  if (!req.session || !req.session.userId) {
    return res.status(401).json({ error: 'No active session' });
  }

  // Sub-step 4.2: Capture identity for audit logging BEFORE destruction
  const userId = req.session.userId;
  console.log(`[AUDIT] User ${userId} logging out at ${new Date().toISOString()}`);

  // Sub-step 4.3: Destroy the server-side session record
  req.session.destroy((err) => {
    if (err) {
      // Step 4.4a: Failure branch
      console.error('Session destruction error:', err);
      return res.status(500).json({ error: 'Logout failed' });
    }

    // Step 4.4b: Success branch — clear the cookie on the client
    res.clearCookie('connect.sid', {
      httpOnly: true,
      secure: false,
      sameSite: 'lax'
    });

    // Step 4.5: Final acknowledgement
    return res.status(200).json({ message: 'Logout successful' });
  });
});
```

**Logic Walkthrough:**
- `req.session.destroy(callback)` removes the session document from MongoDB.
- `res.clearCookie(name, options)` instructs the browser to overwrite the cookie with a past `Expires` date — equivalent to `Max-Age=0`.
- The 200 status is sent **inside** the callback because destruction is asynchronous.

## 3.2 Stateless Logout — JWT Derivation

### Step 1 — Token Issuance at Login

```javascript
const jwt = require('jsonwebtoken');

app.post('/api/login', (req, res) => {
  const { username, password } = req.body;
  if (username === 'admin' && password === 'ktu123') {

    const accessToken = jwt.sign(
      { sub: 'admin-001', role: 'student' },
      process.env.JWT_SECRET || 'ktu-jwt-secret',
      { expiresIn: '15m', jwtid: 'jti-001' }
    );

    const refreshToken = jwt.sign(
      { sub: 'admin-001', type: 'refresh' },
      process.env.REFRESH_SECRET || 'ktu-refresh-secret',
      { expiresIn: '7d', jwtid: 'rt-001' }
    );

    return res.status(200).json({ accessToken, refreshToken });
  }
  return res.status(401).json({ error: 'Invalid credentials' });
});
```

### Step 2 — Logout Endpoint with Token Blacklist

```javascript
// In-memory blacklist (replace with Redis in production)
const tokenBlacklist = new Set();

app.post('/api/logout', (req, res) => {

  // Sub-step 2.1: Extract the bearer token
  const authHeader = req.headers['authorization'];
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Missing token' });
  }
  const token = authHeader.split(' ')[1];

  // Sub-step 2.2: Verify signature to obtain the JTI and exp
  jwt.verify(token, process.env.JWT_SECRET || 'ktu-jwt-secret',
              (err, decoded) => {
    if (err) {
      return res.status(401).json({ error: 'Invalid or expired token' });
    }

    // Sub-step 2.3: Compute remaining lifetime
    const expiresAt   = decoded.exp * 1000;          // convert s → ms
    const now         = Date.now();
    const ttlSeconds  = Math.max(0, Math.floor((expiresAt - now) / 1000));

    // Sub-step 2.4: Push JTI into blacklist with TTL
    tokenBlacklist.add(decoded.jti);

    // Production: use Redis SETEX jti "EX" ttlSeconds
    // redis.setex(`bl:${decoded.jti}`, ttlSeconds, '1');

    // Sub-step 2.5: Optionally clear the refresh token (server-side revoke)
    // db.refreshTokens.deleteOne({ jti: 'rt-001' });

    return res.status(200).json({ message: 'Logout successful' });
  });
});
```

### Step 3 — Middleware That Enforces the Blacklist

```javascript
function authMiddleware(req, res, next) {
  const authHeader = req.headers['authorization'];
  if (!authHeader) return res.status(401).json({ error: 'Unauthenticated' });

  const token = authHeader.split(' ')[1];
  jwt.verify(token, process.env.JWT_SECRET, (err, decoded) => {
    if (err) return res.status(401).json({ error: 'Invalid token' });

    if (tokenBlacklist.has(decoded.jti)) {
      return res.status(401).json({ error: 'Session terminated — please log in again' });
    }
    req.user = decoded;
    next();
  });
}
```

## 3.3 Frontend Coordination (SPA — React Snippet)

```javascript
// logoutHandler.js
async function handleLogout() {
  try {
    const response = await fetch('/api/logout', {
      method: 'POST',
      credentials: 'include',            // send cookies for stateful mode
      headers: { 'Content-Type': 'application/json' }
    });

    if (response.ok) {
      localStorage.removeItem('user');   // clear client cache
      sessionStorage.clear();
      window.location.href = '/login';   // hard redirect to flush React state
    }
  } catch (err) {
    console.error('Logout request failed', err);
  }
}
```

**Logic:** `window.location.href` performs a full page reload, guaranteeing the React tree, Redux store, and any in-memory tokens are wiped — far safer than client-side routing.

## 3.4 Mathematical Justification of Cookie Lifetime

The relationship between cookie attributes and effective logout can be written as:

$$T_{\text{effective}} = T_{\text{server}} \cdot \mathbf{1}_{\text{cookie present}} - T_{\text{cleared}}$$

where:
- $T_{\text{server}}$ is the server-side session TTL,
- $\mathbf{1}_{\text{cookie present}}$ is the indicator function (1 if browser still holds the cookie, 0 otherwise),
- $T_{\text{cleared}}$ is the lifetime the browser subtracts after a `Set-Cookie: Max-Age=0` header.

After a correct logout call, $\mathbf{1}_{\text{cookie present}} = 0$, so $T_{\text{effective}} = 0$ regardless of $T_{\text{server}}$.

