## 3.3 JavaScript Logic — Full Derivation

The JavaScript module implements the state machine. Below is the **exhaustive, line-by-line derivation**.

```javascript
// ============ STATE DECLARATION ============
let currentInput = '0';      // String buffer for digits
let previousInput = '';      // First operand
let operator = null;         // Pending operator
let shouldResetScreen = false; // Flag for next-input behavior

// ============ DOM REFERENCES ============
const display = document.getElementById('display');
const buttons = document.querySelectorAll('.btn');

// ============ CORE COMPUTE FUNCTION ============
function compute(a, b, op) {
  const x = parseFloat(a);
  const y = parseFloat(b);
  switch (op) {
    case 'add':      return x + y;
    case 'subtract': return x - y;
    case 'multiply': return x * y;
    case 'divide':
      if (y === 0) return 'Error';
      return x / y;
    default: return y;
  }
}

// ============ DISPLAY UPDATE ============
function updateDisplay() {
  display.textContent = currentInput;
}

// ============ INPUT HANDLER ============
function inputDigit(digit) {
  if (shouldResetScreen) {
    currentInput = digit;
    shouldResetScreen = false;
  } else {
    currentInput = (currentInput === '0') ? digit : currentInput + digit;
  }
  updateDisplay();
}

function inputDecimal() {
  if (shouldResetScreen) {
    currentInput = '0.';
    shouldResetScreen = false;
    updateDisplay();
    return;
  }
  if (!currentInput.includes('.')) {
    currentInput += '.';
  }
  updateDisplay();
}

// ============ OPERATOR HANDLER ============
function handleOperator(nextOperator) {
  const inputValue = parseFloat(currentInput);

  if (operator && !shouldResetScreen) {
    const result = compute(previousInput, currentInput, operator);
    currentInput = String(result);
    updateDisplay();
    previousInput = currentInput;
  } else {
    previousInput = currentInput;
  }

  shouldResetScreen = true;
  operator = nextOperator;
}

// ============ EQUALS HANDLER ============
function handleEquals() {
  if (operator === null) return;
  const result = compute(previousInput, currentInput, operator);
  currentInput = String(result);
  previousInput = '';
  operator = null;
  shouldResetScreen = true;
  updateDisplay();
}

// ============ UTILITY HANDLERS ============
function handleClear() {
  currentInput = '0';
  previousInput = '';
  operator = null;
  shouldResetScreen = false;
  updateDisplay();
}

function handleSign() {
  if (currentInput === '0') return;
  currentInput = currentInput.startsWith('-')
    ? currentInput.slice(1)
    : '-' + currentInput;
  updateDisplay();
}

function handlePercent() {
  currentInput = String(parseFloat(currentInput) / 100);
  updateDisplay();
}

// ============ EVENT DISPATCHER ============
buttons.forEach(button => {
  button.addEventListener('click', () => {
    const action = button.dataset.action;
    const number  = button.dataset.number;

    if (number !== undefined) {
      inputDigit(number);
    } else if (action === 'decimal') {
      inputDecimal();
    } else if (action === 'clear') {
      handleClear();
    } else if (action === 'sign') {
      handleSign();
    } else if (action === 'percent') {
      handlePercent();
    } else if (['add','subtract','multiply','divide'].includes(action)) {
      handleOperator(action);
    } else if (action === 'equals') {
      handleEquals();
    }
  });
});

// ============ KEYBOARD SUPPORT ============
document.addEventListener('keydown', (e) => {
  if (e.key >= '0' && e.key <= '9') inputDigit(e.key);
  else if (e.key === '.') inputDecimal();
  else if (e.key === '+') handleOperator('add');
  else if (e.key === '-') handleOperator('subtract');
  else if (e.key === '*') handleOperator('multiply');
  else if (e.key === '/') handleOperator('divide');
  else if (e.key === 'Enter' || e.key === '=') handleEquals();
  else if (e.key === 'Escape') handleClear();
  else if (e.key === '%') handlePercent();
});
```

### 3.3.1 Walkthrough: `12 + 7 × 3 = ?`

| Step | User Action | State After |
|------|-------------|-------------|
| 1 | Press `1` | `currentInput="1"` |
| 2 | Press `2` | `currentInput="12"` |
| 3 | Press `+` | `previousInput="12"`, `operator="add"`, `shouldResetScreen=true` |
| 4 | Press `7` | `shouldResetScreen` was true → `currentInput="7"` |
| 5 | Press `×` | Compute `12+7=19`, `currentInput="19"`, `previousInput="19"`, `operator="multiply"`, `shouldResetScreen=true` |
| 6 | Press `3` | `currentInput="3"` |
| 7 | Press `=` | Compute `19×3=57`, displayed as `57` |

**Result: 57** (left-to-right execution, as a real calculator would).

### 3.3.2 Floating-Point Precision Fix

To avoid the famous `0.1 + 0.2 = 0.30000000000000004` artifact, modify `compute`:

```javascript
function roundResult(num) {
  return Math.round((num + Number.EPSILON) * 1e10) / 1e10;
}
```

**Derivation:** The expression `num + Number.EPSILON` shifts the value just above the true mathematical result, after which multiplying by `10^10` pushes the significant digits into the integer range. Rounding, then dividing back, yields a clean decimal.
