**(b) JavaScript State Machine (7 marks):**

```javascript
let currentInput    = '0';
let previousInput   = '';
let operator        = null;
let shouldReset     = false;

const display = document.getElementById('display');

function compute(a, b, op) {
  const x = parseFloat(a);
  const y = parseFloat(b);
  switch (op) {
    case 'add':      return x + y;
    case 'subtract': return x - y;
    case 'multiply': return x * y;
    case 'divide':   return y === 0 ? 'Error' : x / y;
    default:         return y;
  }
}

function inputDigit(d) {
  if (shouldReset) { currentInput = d; shouldReset = false; }
  else currentInput = (currentInput === '0') ? d : currentInput + d;
  display.textContent = currentInput;
}

function handleOperator(op) {
  if (operator && !shouldReset) {
    const r = compute(previousInput, currentInput, operator);
    currentInput = String(r);
    display.textContent = currentInput;
  }
  previousInput = currentInput;
  operator = op;
  shouldReset = true;
}

function handleEquals() {
  if (operator === null) return;
  const r = compute(previousInput, currentInput, operator);
  currentInput = String(r);
  previousInput = '';
  operator = null;
  shouldReset = true;
  display.textContent = currentInput;
}

document.querySelectorAll('.btn').forEach(btn => {
  btn.addEventListener('click', () => {
    const num = btn.dataset.number;
    const act = btn.dataset.action;
    if (num !== undefined)        inputDigit(num);
    else if (act === 'add')      handleOperator('add');
    else if (act === 'subtract') handleOperator('subtract');
    else if (act === 'multiply') handleOperator('multiply');
    else if (act === 'divide')   handleOperator('divide');
    else if (act === 'equals')   handleEquals();
    else if (act === 'clear') {
      currentInput = '0'; previousInput = ''; operator = null; shouldReset = false;
      display.textContent = currentInput;
    }
  });
});
```

**Mark distribution (7 marks):**
- State variable declarations (1 mark)
- `compute()` function with switch-case (2 marks)
- `inputDigit()` with reset logic (1 mark)
- `handleOperator()` that triggers chained computation (2 marks)
- Event listener wiring all buttons (1 mark)

**Trace of left-to-right evaluation:** For `5 + 3 × 2 =`:
1. `5` → `currentInput="5"`
2. `+` → `previousInput="5"`, `operator="add"`, `shouldReset=true`
3. `3` → `currentInput="3"`
4. `×` → compute `5+3=8`, `previousInput="8"`, `operator="multiply"`, `shouldReset=true`
5. `2` → `currentInput="2"`
6. `=` → compute `8×2=16` → displays `16` ✓

