### **Question B (14 Marks) [Alternative Choice – KTU 2024 Scheme]**

**(a)** Explain the **Fisher–Yates shuffle algorithm** in detail. Prove that it generates a uniformly random permutation. Compare its efficiency with the naive `array.sort(() => Math.random() - 0.5)` approach. **(7 marks)**

**(b)** Design and write the complete code (HTML + CSS + JavaScript) for a **4×4 Memory Game** with the following features: **(7 marks)**
   (i) Move counter and score display.  **(2 marks)**
   (ii) A `restart` button that reshuffles and resets state.  **(2 marks)**
   (iii) A win-detection alert when all pairs are matched.  **(3 marks)**

#### Model Solution

**(a) Fisher–Yates Shuffle Explanation (7 marks):**

The Fisher–Yates algorithm shuffles an array of size `n` in-place as follows:

$$ \text{For } i = n-1 \text{ down to } 1: $$

$$ j \leftarrow \text{random integer such that } 0 \leq j \leq i $$

$$ \text{Swap } a[i] \leftrightarrow a[j] $$

**Proof of Uniformity (Inductive):**
- **Base case:** When `n = 1`, only one permutation exists; probability = $1/1! = 1$. ✓
- **Inductive step:** Assume for `k` elements, the algorithm produces a uniform distribution. For `k+1` elements, the last element is chosen uniformly from `k+1` options (probability $1/(k+1)$), and the remaining `k` elements are uniformly shuffled by induction. Hence total permutations = $(k+1) \times k! = (k+1)!$, each with probability $1/(k+1)!$. ✓

**Comparison Table:**

| Method | Time Complexity | Bias | Recommended |
|---|---|---|---|
| Fisher–Yates | $O(n)$ | None (uniform) | ✅ Yes |
| `sort(() => Math.random() - 0.5)` | $O(n \log n)$ | **Biased** (not uniform) | ❌ No |

The `sort()` approach is biased because the comparator is **not transitive** — JavaScript's sort algorithm assumes consistent ordering, which `Math.random()` violates.

**(b) Complete Code (7 marks):**

```html
<!-- (i), (ii), (iii) Combined HTML -->
<!DOCTYPE html>
<html>
<head><title>Memory Game</title></head>
<body>
  <h1>Memory Game</h1>
  <div class="stats">
    <span id="moves">Moves: 0</span>
    <span id="score">Score: 0</span>
  </div>
  <div id="board" class="board"></div>
  <button id="restart">Restart</button>

  <script>
    const symbols = ['A','B','C','D','E','F','G','H'];
    let cards = [];
    let first=null, second=null, locked=false;
    let moves=0, score=0, matched=0;

    function shuffle(a){
      for(let i=a.length-1;i>0;i--){
        const j=Math.floor(Math.random()*(i+1));
        [a[i],a[j]]=[a[j],a[i]];
      }
    }

    function render(){
      const board=document.getElementById('board');
      board.innerHTML='';
      cards.forEach(sym=>{
        const c=document.createElement('div');
        c.className='card'; c.dataset.value=sym; c.textContent='?';
        c.onclick=()=>flip(c);
        board.appendChild(c);
      });
    }

    function flip(c){
      if(locked||c.classList.contains('flipped')||c.classList.contains('matched')) return;
      c.classList.add('flipped'); c.textContent=c.dataset.value;
      if(!first){ first=c; } else {
        second=c; moves++;
        document.getElementById('moves').textContent='Moves: '+moves;
        if(first.dataset.value===second.dataset.value){
          first.classList.add('matched');
          second.classList.add('matched');
          score+=10;
          document.getElementById('score').textContent='Score: '+score;
          matched++;
          if(matched===symbols.length){
            setTimeout(()=>alert('You Win! Score: '+score),300);
          }
          first=second=null;
        } else {
          locked=true;
          setTimeout(()=>{
            first.classList.remove('flipped'); first.textContent='?';
            second.classList.remove('flipped'); second.textContent='?';
            first=second=null; locked=false;
          },1000);
        }
      }
    }

    document.getElementById('restart').onclick=()=>{
      cards=[...symbols,...symbols]; shuffle(cards);
      moves=0; score=0; matched=0; first=second=null; locked=false;
      document.getElementById('moves').textContent='Moves: 0';
      document.getElementById('score').textContent='Score: 0';
      render();
    };

    cards=[...symbols,...symbols]; shuffle(cards); render();
  </script>
</body>
</html>
```

