## 3.7 Step 7 — Search with Debouncing (components/Navbar.jsx)

The search debouncing derivation:

$$ t_{\text{invoke}} = t_{\text{lastKey}} + 400 \text{ ms} $$

If the user types continuously, the timer is reset. The API call fires only **400 ms after the last keystroke**.

```javascript
import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

const Navbar = () => {
  const [query, setQuery] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    const timer = setTimeout(() => {
      if (query.trim()) navigate(`/search?q=${encodeURIComponent(query)}`);
    }, 400);
    return () => clearTimeout(timer);
  }, [query, navigate]);

  return (
    <nav>
      <input
        type="text"
        value={query}
        onChange={e => setQuery(e.target.value)}
        placeholder="Search movies..."
      />
    </nav>
  );
};
```

## 3.8 Step 8 — Movie Detail Page (pages/MovieDetail.jsx)

```javascript
import { useParams } from 'react-router-dom';
import { useEffect, useState } from 'react';
import api, { ENDPOINTS, IMG_BASE } from '../services/api';

const MovieDetail = () => {
  const { id } = useParams();
  const [movie, setMovie] = useState(null);
  const [cast, setCast] = useState([]);

  useEffect(() => {
    const fetchDetail = async () => {
      const [movieRes, creditsRes] = await Promise.all([
        api.get(ENDPOINTS.DETAIL(id)),
        api.get(ENDPOINTS.CREDITS(id))
      ]);
      setMovie(movieRes.data);
      setCast(creditsRes.data.cast.slice(0, 10));
    };
    fetchDetail();
  }, [id]);

  if (!movie) return <div>Loading...</div>;

  return (
    <div className="movie-detail">
      <img src={`${IMG_BASE}${movie.poster_path}`} alt={movie.title} />
      <h1>{movie.title}</h1>
      <p><strong>Rating:</strong> {movie.vote_average} / 10</p>
      <p><strong>Release Date:</strong> {movie.release_date}</p>
      <p>{movie.overview}</p>
      <h2>Top Cast</h2>
      <ul>
        {cast.map(actor => (
          <li key={actor.id}>{actor.name} as {actor.character}</li>
        ))}
      </ul>
    </div>
  );
};
```

**Key derivation:** `Promise.all` runs the two API requests **in parallel**, reducing total wait time from

$$ T_{\text{sequential}} = t_{\text{detail}} + t_{\text{credits}} \approx 2T $$

to

$$ T_{\text{parallel}} = \max(t_{\text{detail}}, t_{\text{credits}}) \approx T $$

This is a **~50% latency reduction** for two independent requests.

