#### **Model Solution for Question A (b) — 7 marks**

**Custom Hook `useFetchMovies` (3.5 marks):**

```javascript
// hooks/useFetchMovies.js
import { useState, useEffect } from 'react';
import api from '../services/api';

const useFetchMovies = (endpoint, params = {}) => {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const controller = new AbortController();
    let isMounted = true;

    const fetchData = async () => {
      try {
        setLoading(true);
        const res = await api.get(endpoint, {
          params,
          signal: controller.signal
        });
        if (isMounted) {
          setData(res.data.results || res.data);
          setError(null);
        }
      } catch (err) {
        if (isMounted && err.name !== 'CanceledError') {
          setError(err.message);
        }
      } finally {
        if (isMounted) setLoading(false);
      }
    };

    fetchData();
    return () => {
      isMounted = false;
      controller.abort();
    };
  }, [endpoint, JSON.stringify(params)]);

  return { data, loading, error };
};

export default useFetchMovies;
```

**Favorites Context `MovieContext` (3.5 marks):**

```javascript
// context/MovieContext.jsx
import { createContext, useContext, useState, useEffect } from 'react';

const MovieContext = createContext();

export const MovieProvider = ({ children }) => {
  // Initialize from localStorage (1 mark)
  const [favorites, setFavorites] = useState(() => {
    try {
      const stored = localStorage.getItem('movie_favorites');
      return stored ? JSON.parse(stored) : [];
    } catch {
      return [];
    }
  });

  // Persist to localStorage on every change (1 mark)
  useEffect(() => {
    localStorage.setItem('movie_favorites', JSON.stringify(favorites));
  }, [favorites]);

  // Toggle helper (0.75 marks)
  const toggleFavorite = (movie) => {
    setFavorites(prev =>
      prev.find(m => m.id === movie.id)
        ? prev.filter(m => m.id !== movie.id)
        : [...prev, movie]
    );
  };

  // Check helper (0.75 marks)
  const isFavorite = (id) => favorites.some(m => m.id === id);

  return (
    <MovieContext.Provider value={{ favorites, toggleFavorite, isFavorite }}>
      {children}
    </MovieContext.Provider>
  );
};

export const useMovieContext = () => {
  const ctx = useContext(MovieContext);
  if (!ctx) throw new Error('useMovieContext must be used inside MovieProvider');
  return ctx;
};
```

