**`MovieCard.jsx` JSX (2.5 marks):**

```javascript
// components/MovieCard.jsx
import { Link } from 'react-router-dom';
import { useMovieContext } from '../context/MovieContext';
import { IMG_BASE } from '../services/endpoints';

const MovieCard = ({ movie }) => {
  const { favorites, toggleFavorite } = useMovieContext();
  const isFav = favorites.some(m => m.id === movie.id);

  const handleFavClick = (e) => {
    e.preventDefault();   // Prevent Link navigation
    e.stopPropagation();
    toggleFavorite(movie);
  };

  return (
    <article className="movie-card">
      <Link to={`/movie/${movie.id}`} className="movie-card-link">
        <img
          src={movie.poster_path
            ? `${IMG_BASE}${movie.poster_path}`
            : '/placeholder.png'}
          alt={movie.title}
          loading="lazy"
        />
        <div className="movie-card-body">
          <h3>{movie.title}</h3>
          <p>⭐ {movie.vote_average?.toFixed(1)} / 10</p>
        </div>
      </Link>
      <button
        className={`fav-btn ${isFav ? 'active' : ''}`}
        onClick={handleFavClick}
        aria-label={isFav ? 'Remove from favorites' : 'Add to favorites'}
      >
        {isFav ? '❤️' : '🤍'}
      </button>
    </article>
  );
};

export default MovieCard;
```

**Key implementation notes (for examiner credit):**
- `e.preventDefault()` and `e.stopPropagation()` on the heart button prevent the parent `<Link>` from navigating when the user only wants to favorite the movie. **(0.5 marks for event handling)**
- `key={movie.id}` on the mapped list ensures React's reconciliation efficiency. **(0.5 marks)**
- `loading="lazy"` improves performance. **(0.5 marks)**

