### 3.2.6 Booking Creation — With Conflict Detection

```javascript
// server/controllers/bookingController.js
import Booking from '../models/Booking.js';
import Room from '../models/Room.js';

export const createBooking = async (req, res) => {
  const { roomId, checkIn, checkOut } = req.body;
  const userId = req.user._id;     // Set by authMiddleware

  // Step 1: Validate dates
  const inDate = new Date(checkIn);
  const outDate = new Date(checkOut);
  if (outDate <= inDate) {
    return res.status(400).json({ message: 'checkOut must be after checkIn' });
  }

  // Step 2: Check for conflicting bookings on the same room
  const conflict = await Booking.findOne({
    room: roomId,
    status: { $in: ['pending', 'confirmed'] },
    $and: [
      { checkIn: { $lt: outDate } },
      { checkOut: { $gt: inDate } }
    ]
  });

  if (conflict) {
    return res.status(409).json({ message: 'Room already booked for selected dates' });
  }

  // Step 3: Compute total price
  const room = await Room.findById(roomId);
  if (!room) return res.status(404).json({ message: 'Room not found' });

  const nights = Math.ceil((outDate - inDate) / (1000 * 60 * 60 * 24));
  const totalPrice = room.price * nights;

  // Step 4: Persist the booking
  const booking = await Booking.create({
    user: userId,
    room: roomId,
    checkIn: inDate,
    checkOut: outDate,
    totalPrice
  });

  res.status(201).json(booking);
};
```

