**Step 2 — Booking Controller with Conflict Detection:**

```javascript
// server/controllers/bookingController.js
import Booking from '../models/Booking.js';
import Room from '../models/Room.js';

export const createBooking = async (req, res) => {
  const { roomId, checkIn, checkOut } = req.body;
  const inD = new Date(checkIn);
  const outD = new Date(checkOut);

  if (outD <= inD)
    return res.status(400).json({ message: 'checkOut must be after checkIn' });

  // Conflict check: overlapping date range on the same room
  const conflict = await Booking.findOne({
    room: roomId,
    status: { $in: ['pending', 'confirmed'] },
    checkIn: { $lt: outD },
    checkOut: { $gt: inD }
  });
  if (conflict)
    return res.status(409).json({ message: 'Room unavailable for these dates' });

  const room = await Room.findById(roomId);
  if (!room) return res.status(404).json({ message: 'Room not found' });

  const nights = Math.ceil((outD - inD) / 86_400_000);   // ms → days
  const totalPrice = room.price * nights;

  const booking = await Booking.create({
    user: req.user._id, room: roomId,
    checkIn: inD, checkOut: outD, totalPrice
  });
  res.status(201).json(booking);
};
```

