## 3.6 Step 5 — Issue/Return Logic (The Core Business Operation)

```javascript
// controllers/transactionController.js
const Transaction = require('../models/Transaction');
const Book        = require('../models/Book');

const FINE_PER_DAY = 2;  // ₹2 per overdue day

// ISSUE A BOOK
exports.issueBook = async (req, res) => {
  const { bookId, days = 14 } = req.body;
  const book = await Book.findById(bookId);

  if (!book)                        return res.status(404).json({ error: 'Book not found' });
  if (book.availableCopies < 1)     return res.status(400).json({ error: 'No copies available' });

  book.availableCopies -= 1;
  await book.save();

  const dueDate = new Date();
  dueDate.setDate(dueDate.getDate() + days);

  const txn = await Transaction.create({
    user: req.user.id, book: bookId, dueDate
  });

  res.status(201).json({ success: true, data: txn });
};

// RETURN A BOOK
exports.returnBook = async (req, res) => {
  const txn  = await Transaction.findById(req.params.id).populate('book');
  if (!txn || txn.status === 'returned')
    return res.status(400).json({ error: 'Invalid transaction' });

  const today    = new Date();
  const overdue  = Math.floor((today - txn.dueDate) / (1000 * 60 * 60 * 24));
  const fine     = overdue > 0 ? overdue * FINE_PER_DAY : 0;

  txn.returnDate = today;
  txn.fine       = fine;
  txn.status     = 'returned';
  await txn.save();

  // Restore inventory
  txn.book.availableCopies += 1;
  await txn.book.save();

  res.status(200).json({ success: true, fine, data: txn });
};
```

**Mathematical Derivation of Fine:**

$$
\text{Overdue Days} = \left\lfloor \frac{T_{\text{return}} - T_{\text{due}}}{86{,}400{,}000 \text{ ms}} \right\rfloor
$$

$$
\text{Fine} = \max(0, \text{Overdue Days}) \times R_{\text{fine}}
$$

Where $86{,}400{,}000$ ms = $24 \times 60 \times 60 \times 1000$ milliseconds in one day, and $R_{\text{fine}} = 2$ ₹/day in this example.
