**(b) Implement JWT-based authentication middleware for the Library App. Show how a user logs in, receives a token, and uses it to access a protected route like `POST /api/books`. (7 marks)**

**Model Solution:**

#### Step 1 — User Login Controller (Token Generation)

```javascript
// controllers/authController.js
const jwt    = require('jsonwebtoken');
const User   = require('../models/User');
const bcrypt = require('bcryptjs');

exports.login = async (req, res) => {
  const { email, password } = req.body;

  // 1. Find user
  const user = await User.findOne({ email });
  if (!user) return res.status(401).json({ error: 'Invalid credentials' });

  // 2. Compare password
  const isMatch = await bcrypt.compare(password, user.password);
  if (!isMatch) return res.status(401).json({ error: 'Invalid credentials' });

  // 3. Generate JWT
  const token = jwt.sign(
    { id: user._id, role: user.role },         // Payload
    process.env.JWT_SECRET,                     // Secret key
    { expiresIn: '1h' }                         // Options
  );

  res.status(200).json({ success: true, token });
};
```

#### Step 2 — JWT Verification Middleware

```javascript
// middleware/auth.js
const jwt = require('jsonwebtoken');

module.exports = (req, res, next) => {
  const authHeader = req.header('Authorization');
  const token = authHeader && authHeader.replace('Bearer ', '');

  if (!token)
    return res.status(401).json({ error: 'Access denied. No token provided.' });

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded;     // Attach {id, role} to request
    next();
  } catch (err) {
    res.status(401).json({ error: 'Invalid token.' });
  }
};
```

#### Step 3 — Role-Based Authorization Middleware (Admin-Only)

```javascript
// middleware/adminAuth.js
module.exports = (req, res, next) => {
  if (req.user.role !== 'admin')
    return res.status(403).json({ error: 'Admin access required.' });
  next();
};
```

#### Step 4 — Applying Middleware to Protected Route

```javascript
// routes/bookRoutes.js
const router       = require('express').Router();
const auth         = require('../middleware/auth');
const adminAuth    = require('../middleware/adminAuth');
const ctrl         = require('../controllers/bookController');

router.post('/',     auth, adminAuth, ctrl.createBook);   // Admin only
router.get('/',      ctrl.getBooks);                     // Public
router.get('/:id',   ctrl.getBook);                      // Public
router.put('/:id',   auth, adminAuth, ctrl.updateBook);  // Admin only
router.delete('/:id',auth, adminAuth, ctrl.deleteBook);  // Admin only

module.exports = router;
```

#### Step 5 — Client-Side Token Usage

```javascript
// public/js/app.js
const token = localStorage.getItem('jwt');

fetch('/api/books', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': `Bearer ${token}`
  },
  body: JSON.stringify({ title: 'Clean Code', author: 'Robert C. Martin', ISBN: '9780132350884' })
})
  .then(res => res.json())
  .then(data => console.log('Book created:', data));
```

> *Marking guide: 2 marks for login + token generation, 2 marks for auth middleware, 2 marks for route protection, 1 mark for client usage.*

